const fs = require('node:fs');
const path = require('node:path');

const rootDir = path.resolve(__dirname, '..');
const sourceDir = path.join(rootDir, 'shared', 'contracts');
const targetDir = path.join(rootDir, 'packages', 'contracts-v2');

const bannerFor = (sourceName) => [
  `// Generated from shared/contracts/${sourceName} by scripts/generate-contract-package.js.`,
  '// Do not edit this file directly; update shared/contracts/v2 and rerun npm run generate:contracts.',
  ''
].join('\n');

const copyGeneratedFile = (sourceName, targetName) => {
  const sourcePath = path.join(sourceDir, sourceName);
  const targetPath = path.join(targetDir, targetName);
  const source = fs.readFileSync(sourcePath, 'utf8');
  fs.mkdirSync(path.dirname(targetPath), { recursive: true });
  fs.writeFileSync(targetPath, `${bannerFor(sourceName)}${source}`, 'utf8');
};

copyGeneratedFile('v2.js', 'index.js');
copyGeneratedFile('v2.d.ts', 'index.d.ts');
console.log('Generated packages/contracts-v2 from shared/contracts/v2');
